import React, { useState } from 'react';
import { MonthlyData } from '../types';
import { ChevronDown, ChevronRight, Plus, Minus } from 'lucide-react';

interface FinancialTableProps {
  data: MonthlyData[];
}

interface RowProps {
  label: string;
  values: number[];
  isHeader?: boolean;
  isSubItem?: boolean;
  isTotal?: boolean;
  isProfit?: boolean;
  isCumulative?: boolean;
  hasChildren?: boolean;
  isOpen?: boolean;
  onToggle?: () => void;
  formatType?: 'default' | 'negative' | 'profit' | 'cumulative';
}

const TableRow: React.FC<RowProps> = ({
  label,
  values,
  isHeader = false,
  isSubItem = false,
  isTotal = false,
  isProfit = false,
  isCumulative = false,
  hasChildren = false,
  isOpen = false,
  onToggle,
  formatType = 'default'
}) => {
  const formatValue = (val: number) => {
    const formatted = Math.round(val).toLocaleString();
    if (formatType === 'negative') return `-${formatted}`;
    if (formatType === 'profit' || formatType === 'cumulative') {
        return val >= 0 ? `+${formatted}` : formatted;
    }
    return formatted;
  };

  const getRowClass = () => {
    if (isProfit) return "bg-blue-50/80 hover:bg-blue-100/80 font-bold border-t-2 border-blue-200";
    if (isCumulative) return "bg-slate-800 text-white font-bold";
    if (isHeader) return "bg-gray-50/80 hover:bg-gray-100 font-bold text-gray-900 border-t border-gray-200";
    if (isSubItem) return "bg-white hover:bg-indigo-50/30 text-xs text-gray-500 italic";
    return "bg-white hover:bg-gray-50 text-gray-700 border-t border-gray-100";
  };

  const getValueClass = (val: number) => {
    if (isCumulative) return val >= 0 ? "text-emerald-400" : "text-rose-400";
    if (isProfit) return val >= 0 ? "text-blue-700" : "text-rose-600";
    if (formatType === 'negative') return "text-rose-500/80";
    return "";
  };

  return (
    <tr className={`${getRowClass()} transition-colors group`}>
      <td 
        className={`px-4 py-3 text-left sticky left-0 z-20 whitespace-nowrap border-r border-gray-200/50 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)] ${isCumulative ? 'bg-slate-800' : 'bg-inherit'}`}
        onClick={onToggle}
        style={{ cursor: hasChildren ? 'pointer' : 'default' }}
      >
        <div className={`flex items-center ${isSubItem ? 'pl-8' : 'pl-1'}`}>
          {hasChildren && (
            <span className="mr-2 text-gray-400 group-hover:text-indigo-600">
              {isOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
            </span>
          )}
          <span className={isTotal ? 'tracking-tight' : ''}>{label}</span>
        </div>
      </td>
      {values.map((val, idx) => (
        <td key={idx} className={`px-4 py-3 text-right whitespace-nowrap font-mono ${getValueClass(val)}`}>
          {formatValue(val)}
        </td>
      ))}
    </tr>
  );
};

export const FinancialTable: React.FC<FinancialTableProps> = ({ data }) => {
  const [expanded, setExpanded] = useState<Record<string, boolean>>({
    revenue: true,
    cogs: false,
    fixed: false
  });

  const toggle = (section: string) => {
    setExpanded(prev => ({ ...prev, [section]: !prev[section] }));
  };

  return (
    <div className="relative overflow-hidden rounded-2xl border border-gray-200 shadow-sm bg-white">
      <div className="overflow-x-auto scrollbar-hide">
        <table className="w-full text-sm border-collapse">
          <thead>
            <tr className="bg-slate-50 text-slate-500 font-bold text-[11px] uppercase tracking-wider border-b border-gray-200">
              <th className="px-4 py-4 text-left sticky left-0 bg-slate-50 z-30 border-r border-gray-200 min-w-[180px]">구분 (단위: 원)</th>
              {data.map(row => (
                <th key={row.month} className="px-4 py-4 text-right min-w-[110px]">Month {row.month}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {/* 1. REVENUE SECTION */}
            <TableRow 
              label="매출액 합계 (Total Revenue)" 
              values={data.map(d => d.revenue)} 
              isHeader 
              hasChildren 
              isOpen={expanded.revenue} 
              onToggle={() => toggle('revenue')}
            />
            {expanded.revenue && (
              <>
                <TableRow label="└ 카페 매출" values={data.map(d => d.cafeRevenue)} isSubItem />
                <TableRow label="└ 공간대여 매출" values={data.map(d => d.spaceRevenue)} isSubItem />
                <TableRow label="└ 와인바 매출" values={data.map(d => d.wineRevenue)} isSubItem />
              </>
            )}

            {/* 2. COGS SECTION */}
            <TableRow 
              label="매출원가/변동비 (Variable Costs)" 
              values={data.map(d => d.cogs)} 
              isHeader 
              hasChildren 
              isOpen={expanded.cogs} 
              onToggle={() => toggle('cogs')}
              formatType="negative"
            />
            {expanded.cogs && (
              <>
                <TableRow label="└ 카페 재료비" values={data.map(d => d.cafeCOGS)} isSubItem formatType="negative" />
                <TableRow label="└ 와인바 원가" values={data.map(d => d.wineCOGS)} isSubItem formatType="negative" />
              </>
            )}

            {/* 3. FIXED COSTS SECTION */}
            <TableRow 
              label="판매관리비/고정비 (Fixed Costs)" 
              values={data.map(d => d.fixedCosts)} 
              isHeader 
              hasChildren 
              isOpen={expanded.fixed} 
              onToggle={() => toggle('fixed')}
              formatType="negative"
            />
            {expanded.fixed && (
              <>
                <TableRow label="└ 총 인건비" values={data.map(d => d.laborCost)} isSubItem formatType="negative" />
                <TableRow label="└ 공과금" values={data.map(d => d.utilityCost)} isSubItem formatType="negative" />
                <TableRow label="└ 마케팅/기타" values={data.map(d => d.otherFixedCost)} isSubItem formatType="negative" />
              </>
            )}

            {/* 4. NET PROFIT */}
            <TableRow 
              label="당월 순이익 (Net Profit)" 
              values={data.map(d => d.netProfit)} 
              isProfit 
              formatType="profit"
            />

            {/* 5. CUMULATIVE PROFIT */}
            <TableRow 
              label="누적 손익 (Cumulative / BEP)" 
              values={data.map(d => d.cumulativeProfit)} 
              isCumulative 
              formatType="cumulative"
            />
          </tbody>
        </table>
      </div>
      <div className="bg-gray-50 px-4 py-2 border-t border-gray-200 text-[10px] text-gray-400 flex justify-between">
        <span>* 항목명을 클릭하여 상세 내역을 펼치거나 접을 수 있습니다.</span>
        <span>ⓒ BizPlanner Financial System</span>
      </div>
    </div>
  );
};

