import React, { useState, useMemo, useEffect } from 'react';
import {
  Coffee,
  Calculator,
  CheckSquare,
  TrendingUp,
  Sparkles,
  Trash2,
  Plus,
  BarChart2,
  Save,
  Copy,
  Layout
} from 'lucide-react';

import { DEFAULT_CONFIG, INITIAL_TODOS, PLAN_PRESETS } from './constants';
import { GlobalConfig, MonthlyData, TodoItem, CafeUnitCosts, Scenario } from './types';
import { DashboardTab } from './components/DashboardTab';
import { PlannerTab } from './components/PlannerTab';
import { TodoTab } from './components/TodoTab';
import { ComparisonTab } from './components/ComparisonTab';

enum Tab {
  DASHBOARD = 'dashboard',
  PLANNER = 'planner',
  COMPARISON = 'comparison',
  TODO = 'todo',
}

const WEEKDAY_MONTHLY_RATE = 2156880; 
const WEEKEND_MONTHLY_RATE = 861200;  

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.DASHBOARD);
  const [config, setConfig] = useState<GlobalConfig>(DEFAULT_CONFIG);
  const [scenarios, setScenarios] = useState<Scenario[]>([]);
  const [activeScenarioId, setActiveScenarioId] = useState<string | null>(null);
  const [todos, setTodos] = useState<TodoItem[]>(INITIAL_TODOS);
  const [projectionMonths, setProjectionMonths] = useState(12);

  useEffect(() => {
    const saved = localStorage.getItem('terrazza_scenarios');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setScenarios(parsed);
      } catch (e) {
        console.error("Failed to parse saved scenarios");
      }
    }
  }, []);

  const saveCurrentScenario = (name: string) => {
    const newScenario: Scenario = {
      id: crypto.randomUUID(),
      name,
      config: JSON.parse(JSON.stringify(config)),
      timestamp: Date.now()
    };
    const updated = [...scenarios, newScenario];
    setScenarios(updated);
    localStorage.setItem('terrazza_scenarios', JSON.stringify(updated));
    setActiveScenarioId(newScenario.id);
  };

  const applyPreset = (presetName: string) => {
    const preset = PLAN_PRESETS[presetName];
    if (preset) {
      setConfig(prev => ({ ...prev, ...preset }));
      setActiveScenarioId(null);
    }
  };

  const loadScenario = (id: string) => {
    const scenario = scenarios.find(s => s.id === id);
    if (scenario) {
      setConfig(JSON.parse(JSON.stringify(scenario.config)));
      setActiveScenarioId(id);
    }
  };

  const deleteScenario = (id: string) => {
    const updated = scenarios.filter(s => s.id !== id);
    setScenarios(updated);
    localStorage.setItem('terrazza_scenarios', JSON.stringify(updated));
    if (activeScenarioId === id) setActiveScenarioId(null);
  };

  const cafeUnitCosts: CafeUnitCosts = useMemo(() => {
    const { beanPricePerKg, milkPricePerL, iceRatio, takeoutRatio } = config.cafe;
    const s = config.cafeSupplies;

    const bean = (beanPricePerKg / 1000) * s.beanGrams;
    const milk = (milkPricePerL / 1000) * s.milkMl;
    const water = s.water;
    const ice = s.ice;
    const syrup = s.syrup;

    const getMenuCost = (menu: 'am' | 'lt' | 'sl', type: 'to' | 'st', temp: 'h' | 'i') => {
      let ing = bean;
      if (menu === 'am') ing += water;
      else if (menu === 'lt') ing += milk;
      else ing += milk + syrup;

      if (temp === 'i') ing += ice;

      let pkg = 0;
      if (type === 'to') {
        pkg = temp === 'h' 
          ? (s.hotCup + s.hotLid + s.stick + s.holder + s.carrier + s.wipe + s.napkin) 
          : (s.iceCup + s.iceLid + s.straw + s.holder + s.carrier + s.wipe + s.napkin);
      } else {
        pkg = s.wipe + s.napkin + s.dishwashing + (temp === 'h' ? s.stick : s.straw);
      }
      return ing + pkg;
    };

    const products = {
      takeout: {
        hot: {
          americano: getMenuCost('am', 'to', 'h'),
          latte: getMenuCost('lt', 'to', 'h'),
          syrupLatte: getMenuCost('sl', 'to', 'h'),
        },
        ice: {
          americano: getMenuCost('am', 'to', 'i'),
          latte: getMenuCost('lt', 'to', 'i'),
          syrupLatte: getMenuCost('sl', 'to', 'i'),
        }
      },
      store: {
        hot: {
          americano: getMenuCost('am', 'st', 'h'),
          latte: getMenuCost('lt', 'st', 'h'),
          syrupLatte: getMenuCost('sl', 'st', 'h'),
        },
        ice: {
          americano: getMenuCost('am', 'st', 'i'),
          latte: getMenuCost('lt', 'st', 'i'),
          syrupLatte: getMenuCost('sl', 'st', 'i'),
        }
      }
    };

    const calcWeighted = (m: 'americano' | 'latte' | 'syrupLatte') => {
      const toH = products.takeout.hot[m];
      const toI = products.takeout.ice[m];
      const stH = products.store.hot[m];
      const stI = products.store.ice[m];

      const toWeighted = toI * iceRatio + toH * (1 - iceRatio);
      const stWeighted = stI * iceRatio + stH * (1 - iceRatio);
      return toWeighted * takeoutRatio + stWeighted * (1 - takeoutRatio);
    };

    return {
      unitCosts: { bean, milk, water, ice, syrup },
      finalCostAmericano: calcWeighted('americano'),
      finalCostLatte: calcWeighted('latte'),
      finalCostSyrupLatte: calcWeighted('syrupLatte'),
      products
    };
  }, [config.cafe, config.cafeSupplies]);

  const calculateFinancials = (cfg: GlobalConfig, uc: CafeUnitCosts) => {
    const { seatCount, operatingHours, stayDuration, turnoverTarget, ratioAmericano, ratioLatte, ratioSyrupLatte, avgPriceAmericano, avgPriceLatte, avgPriceSyrupLatte, operatingDays: cafeDays } = cfg.cafe;
    const { hourlyRate, hoursPerDay, operatingDays: spaceDays, utilizationRate } = cfg.space;
    const { avgTicketPrice, dailyTables, operatingDays: wineDays, costOfGoodsSoldRate } = cfg.wine;
    const { weekdayStaff, weekendStaff, additionalLabor, utilities, internet, marketing, maintenance, misc } = cfg.fixed;

    const safeStayDuration = stayDuration > 0 ? stayDuration : 1;
    const maxDailyCapacity = seatCount * (operatingHours / safeStayDuration);
    const salesCount = Math.round(maxDailyCapacity * turnoverTarget);

    const laborCost = (weekdayStaff * WEEKDAY_MONTHLY_RATE) + (weekendStaff * WEEKEND_MONTHLY_RATE) + additionalLabor;

    const weightedAvgPrice = avgPriceAmericano * ratioAmericano + avgPriceLatte * ratioLatte + avgPriceSyrupLatte * ratioSyrupLatte;
    const weightedAvgCost = uc.finalCostAmericano * ratioAmericano + uc.finalCostLatte * ratioLatte + uc.finalCostSyrupLatte * ratioSyrupLatte;

    const cafeRevenue = weightedAvgPrice * salesCount * cafeDays;
    const cafeCOGS = weightedAvgCost * salesCount * cafeDays;
    const spaceRevenue = hourlyRate * hoursPerDay * utilizationRate * spaceDays;
    const wineRevenue = avgTicketPrice * dailyTables * wineDays;
    const wineCOGS = wineRevenue * costOfGoodsSoldRate;

    const totalRevenue = cafeRevenue + spaceRevenue + wineRevenue;
    const totalCOGS = cafeCOGS + wineCOGS;
    const totalFixed = laborCost + utilities + internet + marketing + maintenance + misc;
    const netProfit = (totalRevenue - totalCOGS) - totalFixed;
    const totalInvestment = Object.values(cfg.initial).reduce((a, b) => a + b, 0);

    return { totalRevenue, netProfit, totalInvestment, salesCount, cafeRevenue, spaceRevenue, wineRevenue, laborCost, totalFixed, cafeCOGS, wineCOGS, totalCOGS };
  };

  const currentFinancials = useMemo(() => calculateFinancials(config, cafeUnitCosts), [config, cafeUnitCosts]);

  const monthlyData: MonthlyData[] = useMemo(() => {
    const data: MonthlyData[] = [];
    let cumulativeProfit = -currentFinancials.totalInvestment;

    for (let m = 1; m <= projectionMonths; m++) {
      cumulativeProfit += currentFinancials.netProfit;
      data.push({
        month: m,
        cafeRevenue: currentFinancials.cafeRevenue,
        spaceRevenue: currentFinancials.spaceRevenue,
        wineRevenue: currentFinancials.wineRevenue,
        revenue: currentFinancials.totalRevenue,
        cafeCOGS: currentFinancials.cafeCOGS,
        wineCOGS: currentFinancials.wineCOGS,
        laborCost: currentFinancials.laborCost,
        utilityCost: config.fixed.utilities,
        otherFixedCost: config.fixed.marketing + config.fixed.internet + config.fixed.maintenance + config.fixed.misc,
        cogs: currentFinancials.totalCOGS,
        grossProfit: currentFinancials.totalRevenue - currentFinancials.totalCOGS,
        fixedCosts: currentFinancials.totalFixed,
        netProfit: currentFinancials.netProfit,
        cumulativeProfit,
      });
    }
    return data;
  }, [currentFinancials, projectionMonths, config]);

  const bepMonth = useMemo(() => {
    const match = monthlyData.find(d => d.cumulativeProfit >= 0);
    return match ? `M+${match.month}` : '측정 불가';
  }, [monthlyData]);

  const calculateFinancialsForScenario = (cfg: GlobalConfig) => {
    const tempUc = (() => {
      const { beanPricePerKg, milkPricePerL, iceRatio, takeoutRatio } = cfg.cafe;
      const s = cfg.cafeSupplies;
      const bean = (beanPricePerKg / 1000) * s.beanGrams;
      const milk = (milkPricePerL / 1000) * s.milkMl;
      const water = s.water;
      const ice = s.ice;
      const syrup = s.syrup;

      const getMenuCost = (menu: 'am' | 'lt' | 'sl', type: 'to' | 'st', temp: 'h' | 'i') => {
        let ing = bean;
        if (menu === 'am') ing += water; else if (menu === 'lt') ing += milk; else ing += milk + syrup;
        if (temp === 'i') ing += ice;
        let pkg = 0;
        if (type === 'to') {
          pkg = temp === 'h' ? (s.hotCup + s.hotLid + s.stick + s.holder + s.carrier + s.wipe + s.napkin) : (s.iceCup + s.iceLid + s.straw + s.holder + s.carrier + s.wipe + s.napkin);
        } else {
          pkg = s.wipe + s.napkin + s.dishwashing + (temp === 'h' ? s.stick : s.straw);
        }
        return ing + pkg;
      };

      const calcWeighted = (m: 'am' | 'lt' | 'sl') => {
        const toH = getMenuCost(m, 'to', 'h');
        const toI = getMenuCost(m, 'to', 'i');
        const stH = getMenuCost(m, 'st', 'h');
        const stI = getMenuCost(m, 'st', 'i');
        const toWeighted = toI * iceRatio + toH * (1 - iceRatio);
        const stWeighted = stI * iceRatio + stH * (1 - iceRatio);
        return toWeighted * takeoutRatio + stWeighted * (1 - takeoutRatio);
      };

      return {
        finalCostAmericano: calcWeighted('am'),
        finalCostLatte: calcWeighted('lt'),
        finalCostSyrupLatte: calcWeighted('sl'),
      };
    })();

    const fin = calculateFinancials(cfg, tempUc as any);
    return {
      totalRevenue: fin.totalRevenue,
      netProfit: fin.netProfit,
      totalInvestment: fin.totalInvestment
    };
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] font-sans text-[#3e2723] pb-20">
      <header className="bg-white border-b border-orange-100 sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center space-x-3">
              <div className="bg-[#5d4037] p-2 rounded-xl shadow-orange-100 shadow-lg">
                <Layout className="text-white h-6 w-6" />
              </div>
              <div>
                <span className="font-bold text-xl tracking-tight block leading-none text-[#5d4037]">Terrazza</span>
                <span className="text-[10px] text-orange-600 font-bold uppercase tracking-widest">Business Planner</span>
              </div>
            </div>

            <nav className="flex space-x-1 bg-orange-50/50 p-1 rounded-xl">
              {[
                { id: Tab.DASHBOARD, label: '대시보드', icon: <TrendingUp size={16} /> },
                { id: Tab.PLANNER, label: '사업 설정', icon: <Calculator size={16} /> },
                { id: Tab.COMPARISON, label: '계획 비교', icon: <Copy size={16} /> },
                { id: Tab.TODO, label: '준비물', icon: <CheckSquare size={16} /> },
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as Tab)}
                  className={`flex items-center space-x-2 px-3 sm:px-5 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === tab.id ? 'bg-white text-[#5d4037] shadow-sm ring-1 ring-orange-100' : 'text-slate-500 hover:text-[#5d4037]'}`}
                >
                  {tab.icon}
                  <span className="hidden md:inline">{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>

        <div className="bg-[#fff9f5] border-b border-orange-100 py-2.5">
          <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-3">
            <div className="flex items-center gap-3 w-full md:w-auto">
              <span className="text-[10px] font-black text-orange-300 uppercase whitespace-nowrap">Plan Presets:</span>
              <div className="flex gap-1.5 overflow-x-auto pb-1 md:pb-0 scrollbar-hide">
                {Object.keys(PLAN_PRESETS).map(name => (
                  <button 
                    key={name}
                    onClick={() => applyPreset(name)}
                    className="px-3 py-1 bg-white border border-orange-100 rounded-full text-[11px] font-bold text-[#5d4037] hover:border-orange-300 hover:bg-orange-50 transition-colors whitespace-nowrap shadow-sm"
                  >
                    {name}
                  </button>
                ))}
              </div>
            </div>
            <div className="flex items-center gap-3 w-full md:w-auto border-t md:border-t-0 pt-2 md:pt-0 border-orange-50">
               <span className="text-[10px] font-black text-orange-300 uppercase whitespace-nowrap">Saved Plans:</span>
               <div className="flex gap-1.5 overflow-x-auto scrollbar-hide">
                {scenarios.map(s => (
                  <div key={s.id} className={`flex items-center bg-white border rounded-full pl-3 pr-1 h-7 shadow-sm transition-all ${activeScenarioId === s.id ? 'border-orange-500 ring-2 ring-orange-50' : 'border-orange-100'}`}>
                    <button onClick={() => loadScenario(s.id)} className={`text-[11px] font-bold mr-2 ${activeScenarioId === s.id ? 'text-orange-700' : 'text-[#5d4037]'}`}>
                      {s.name}
                    </button>
                    <button onClick={() => deleteScenario(s.id)} className="p-1 text-orange-200 hover:text-rose-500 rounded-full hover:bg-rose-50"><Trash2 size={12} /></button>
                  </div>
                ))}
                <button 
                  onClick={() => { const name = prompt("계획 이름을 입력하세요:"); if(name) saveCurrentScenario(name); }} 
                  className="px-3 h-7 bg-[#5d4037] text-white rounded-full text-[11px] font-bold flex items-center gap-1.5 shadow-md hover:bg-[#4e342e] transition-all"
                >
                  <Save size={12}/> 저장
                </button>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {activeTab === Tab.DASHBOARD && (
          <DashboardTab 
            monthlyData={monthlyData}
            totalInvestment={currentFinancials.totalInvestment}
            bepMonth={bepMonth}
          />
        )}

        {activeTab === Tab.PLANNER && (
          <PlannerTab 
            config={config}
            onConfigChange={(s, f, v) => setConfig(prev => ({...prev, [s]: {...prev[s], [f]: v}}))}
            onSupplyChange={(f, v) => setConfig(prev => ({...prev, cafeSupplies: {...prev.cafeSupplies, [f]: v}}))}
            monthlyData={monthlyData}
            dailySalesCount={currentFinancials.salesCount}
            cafeUnitCosts={cafeUnitCosts} 
            totalInvestment={currentFinancials.totalInvestment}
            calculatedLaborCost={currentFinancials.laborCost}
          />
        )}

        {activeTab === Tab.COMPARISON && (
          <ComparisonTab scenarios={scenarios} calculateFinancials={calculateFinancialsForScenario} />
        )}

        {activeTab === Tab.TODO && (
          <TodoTab todos={todos} onToggle={(id) => setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t))} />
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { MonthlyData } from '../types';
import { ChevronDown, ChevronRight } from 'lucide-react';

interface FinancialTableProps {
  data: MonthlyData[];
}

interface RowProps {
  label: string;
  values: number[];
  isHeader?: boolean;
  isSubItem?: boolean;
  isTotal?: boolean;
  isProfit?: boolean;
  isCumulative?: boolean;
  hasChildren?: boolean;
  isOpen?: boolean;
  onToggle?: () => void;
  formatType?: 'default' | 'negative' | 'profit' | 'cumulative';
}

const TableRow: React.FC<RowProps> = ({
  label,
  values,
  isHeader = false,
  isSubItem = false,
  isProfit = false,
  isCumulative = false,
  hasChildren = false,
  isOpen = false,
  onToggle,
  formatType = 'default'
}) => {
  const formatValue = (val: number) => {
    const formatted = Math.round(val).toLocaleString();
    if (formatType === 'negative') return `-${formatted}`;
    if (formatType === 'profit' || formatType === 'cumulative') {
        return val >= 0 ? `+${formatted}` : formatted;
    }
    return formatted;
  };

  const getRowClass = () => {
    if (isProfit) return "bg-orange-50 hover:bg-orange-100/50 font-bold border-t-2 border-orange-200";
    if (isCumulative) return "bg-[#3e2723] text-white font-bold";
    if (isHeader) return "bg-[#faf7f5] hover:bg-[#f3efec] font-bold text-[#5d4037] border-t border-orange-100";
    if (isSubItem) return "bg-white hover:bg-orange-50/30 text-xs text-[#8d6e63] italic";
    return "bg-white hover:bg-orange-50/50 text-[#5d4037] border-t border-orange-50";
  };

  const getValueClass = (val: number) => {
    if (isCumulative) return val >= 0 ? "text-emerald-400" : "text-rose-400";
    if (isProfit) return val >= 0 ? "text-orange-700" : "text-rose-600";
    if (formatType === 'negative') return "text-rose-500/80";
    return "";
  };

  return (
    <tr className={`${getRowClass()} transition-colors group`}>
      <td 
        className={`px-4 py-3 text-left sticky left-0 z-20 whitespace-nowrap border-r border-orange-100/50 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.03)] ${isCumulative ? 'bg-[#3e2723]' : 'bg-inherit'}`}
        onClick={onToggle}
        style={{ cursor: hasChildren ? 'pointer' : 'default' }}
      >
        <div className={`flex items-center ${isSubItem ? 'pl-8' : 'pl-1'}`}>
          {hasChildren && (
            <span className="mr-2 text-orange-300 group-hover:text-orange-600">
              {isOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
            </span>
          )}
          <span>{label}</span>
        </div>
      </td>
      {values.map((val, idx) => (
        <td key={idx} className={`px-4 py-3 text-right whitespace-nowrap font-mono ${getValueClass(val)}`}>
          {formatValue(val)}
        </td>
      ))}
    </tr>
  );
};

export const FinancialTable: React.FC<FinancialTableProps> = ({ data }) => {
  const [expanded, setExpanded] = useState<Record<string, boolean>>({
    revenue: true,
    cogs: false,
    fixed: false
  });

  const toggle = (section: string) => {
    setExpanded(prev => ({ ...prev, [section]: !prev[section] }));
  };

  return (
    <div className="relative overflow-hidden rounded-2xl border border-orange-100 shadow-sm bg-white">
      <div className="overflow-x-auto scrollbar-hide">
        <table className="w-full text-sm border-collapse">
          <thead>
            <tr className="bg-[#fff9f5] text-[#8d6e63] font-bold text-[11px] uppercase tracking-wider border-b border-orange-100">
              <th className="px-4 py-4 text-left sticky left-0 bg-[#fff9f5] z-30 border-r border-orange-100 min-w-[180px]">항목 구분</th>
              {data.map(row => (
                <th key={row.month} className="px-4 py-4 text-right min-w-[110px]">M+{row.month}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            <TableRow 
              label="총 매출 (Total Revenue)" 
              values={data.map(d => d.revenue)} 
              isHeader 
              hasChildren 
              isOpen={expanded.revenue} 
              onToggle={() => toggle('revenue')}
            />
            {expanded.revenue && (
              <>
                <TableRow label="└ 카페 매출" values={data.map(d => d.cafeRevenue)} isSubItem />
                <TableRow label="└ 공간대여 매출" values={data.map(d => d.spaceRevenue)} isSubItem />
                <TableRow label="└ 와인바 매출" values={data.map(d => d.wineRevenue)} isSubItem />
              </>
            )}

            <TableRow 
              label="총 매출원가 (COGS)" 
              values={data.map(d => d.cogs)} 
              isHeader 
              hasChildren 
              isOpen={expanded.cogs} 
              onToggle={() => toggle('cogs')}
              formatType="negative"
            />
            {expanded.cogs && (
              <>
                <TableRow label="└ 카페 재료비" values={data.map(d => d.cafeCOGS)} isSubItem formatType="negative" />
                <TableRow label="└ 와인바 원가" values={data.map(d => d.wineCOGS)} isSubItem formatType="negative" />
              </>
            )}

            <TableRow 
              label="총 고정비 (Fixed Costs)" 
              values={data.map(d => d.fixedCosts)} 
              isHeader 
              hasChildren 
              isOpen={expanded.fixed} 
              onToggle={() => toggle('fixed')}
              formatType="negative"
            />
            {expanded.fixed && (
              <>
                <TableRow label="└ 인건비 합계" values={data.map(d => d.laborCost)} isSubItem formatType="negative" />
                <TableRow label="└ 공과금" values={data.map(d => d.utilityCost)} isSubItem formatType="negative" />
                <TableRow label="└ 기타 운영비" values={data.map(d => d.otherFixedCost)} isSubItem formatType="negative" />
              </>
            )}

            <TableRow 
              label="당월 순이익 (Net Profit)" 
              values={data.map(d => d.netProfit)} 
              isProfit 
              formatType="profit"
            />

            <TableRow 
              label="누적 손익 (Cumulative)" 
              values={data.map(d => d.cumulativeProfit)} 
              isCumulative 
              formatType="cumulative"
            />
          </tbody>
        </table>
      </div>
      <div className="bg-[#fff9f5] px-4 py-2 border-t border-orange-100 text-[10px] text-orange-300 flex justify-between italic">
        <span>* 항목명을 클릭하면 세부 데이터 확인이 가능합니다.</span>
        <span>Terrazza Lounge Financial System v1.2</span>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import {
  Line,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ComposedChart,
  ReferenceLine,
  PieChart,
  Pie,
  Cell
} from 'recharts';
import {
  TrendingUp,
  DollarSign,
  AlertCircle,
  Calculator,
  PieChart as PieChartIcon,
  FileText
} from 'lucide-react';
import { MonthlyData } from '../types';
import { InfoCard } from './InfoCard';
import { FinancialTable } from './FinancialTable';

const CHART_COLORS = {
  revenue: { cafe: '#795548', space: '#fb8c00', wine: '#bf360c' },
  cost: { labor: '#5d4037', cafe: '#8d6e63', wine: '#a1887f', utility: '#d7ccc8', fixed: '#efebe9' },
  profit: '#3e2723'
};

interface DashboardTabProps {
  monthlyData: MonthlyData[];
  totalInvestment: number;
  bepMonth: string;
}

export const DashboardTab: React.FC<DashboardTabProps> = ({ 
  monthlyData, 
  totalInvestment, 
  bepMonth,
}) => {
  const mainChartData = useMemo(() => {
    return monthlyData.map(d => ({
      ...d,
      cafeCOGS: -d.cafeCOGS,
      wineCOGS: -d.wineCOGS,
      laborCost: -d.laborCost,
      utilityCost: -d.utilityCost,
      otherFixedCost: -d.otherFixedCost,
    }));
  }, [monthlyData]);

  const pieChartData = useMemo(() => {
    const current = monthlyData[0];
    if (!current) return { revenue: [], cost: [] };
    const revenue = [
      { name: '카페 매출', value: current.cafeRevenue, color: CHART_COLORS.revenue.cafe },
      { name: '공간대여 매출', value: current.spaceRevenue, color: CHART_COLORS.revenue.space },
      { name: '와인바 매출', value: current.wineRevenue, color: CHART_COLORS.revenue.wine },
    ].filter(d => d.value > 0);
    const cost = [
      { name: '카페 재료비', value: current.cafeCOGS, color: CHART_COLORS.cost.cafe },
      { name: '와인 재료비', value: current.wineCOGS, color: CHART_COLORS.cost.wine },
      { name: '인건비', value: current.laborCost, color: CHART_COLORS.cost.labor },
      { name: '공과금', value: current.utilityCost, color: CHART_COLORS.cost.utility },
      { name: '기타 고정비', value: current.otherFixedCost, color: CHART_COLORS.cost.fixed },
    ].filter(d => d.value > 0);
    return { revenue, cost };
  }, [monthlyData]);

  const { totalRevenue, totalCost } = useMemo(() => {
    const r = pieChartData.revenue.reduce((acc, cur) => acc + cur.value, 0);
    const c = pieChartData.cost.reduce((acc, cur) => acc + cur.value, 0);
    return { totalRevenue: r, totalCost: c };
  }, [pieChartData]);

  return (
    <div className="space-y-8 pb-12">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <InfoCard title="월 예상 총 매출" value={`₩${Math.round(totalRevenue / 10000).toLocaleString()}만`} subValue="사업부별 합산 결과" icon={<TrendingUp className="text-orange-600" />} />
        <InfoCard title="월 예상 순수익" value={`₩${Math.round((monthlyData[0]?.netProfit || 0) / 10000).toLocaleString()}만`} subValue={`영업이익률 ${totalRevenue ? Math.round((monthlyData[0].netProfit / totalRevenue) * 100) : 0}%`} icon={<DollarSign className="text-orange-800" />} />
        <InfoCard title="초기 투자 예산" value={`₩${Math.round(totalInvestment / 10000).toLocaleString()}만`} subValue="시설 및 집기류 포함" icon={<Calculator className="text-brown-500" />} />
        <InfoCard title="회수 시점 (BEP)" value={bepMonth} subValue={bepMonth !== '측정 불가' ? '수익 전환 예상 시점' : '운영 전략 재검토 권장'} icon={<AlertCircle className="text-orange-400" />} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-orange-100">
           <div className="flex justify-between items-center mb-4"><h2 className="text-lg font-bold text-[#5d4037] flex items-center gap-2"><PieChartIcon size={20} className="text-orange-600"/> 매출 비중</h2></div>
           <div className="h-[250px] w-full relative">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={pieChartData.revenue} cx="50%" cy="50%" labelLine={false} outerRadius={90} innerRadius={40} fill="#8884d8" dataKey="value" nameKey="name">
                    {pieChartData.revenue.map((entry, index) => (<Cell key={`cell-${index}`} fill={entry.color} stroke="white" strokeWidth={2} />))}
                  </Pie>
                  <Tooltip formatter={(value: number, name: string) => [`₩${Math.round(value).toLocaleString()}`, name]} />
                  <Legend layout="vertical" verticalAlign="middle" align="right" wrapperStyle={{fontSize: '11px'}}/>
                </PieChart>
              </ResponsiveContainer>
              <div className="absolute top-0 right-0 text-right bg-orange-50/50 p-2 rounded-lg border border-orange-100 shadow-sm"><div className="text-[10px] text-orange-600 font-bold uppercase">Total Revenue</div><div className="text-lg font-bold text-[#5d4037]">₩{Math.round(totalRevenue / 10000).toLocaleString()}만</div></div>
           </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-orange-100">
           <div className="flex justify-between items-center mb-4"><h2 className="text-lg font-bold text-[#5d4037] flex items-center gap-2"><PieChartIcon size={20} className="text-orange-800"/> 지출 구조</h2></div>
           <div className="h-[250px] w-full relative">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={pieChartData.cost} cx="50%" cy="50%" labelLine={false} outerRadius={90} innerRadius={40} fill="#8884d8" dataKey="value" nameKey="name">
                    {pieChartData.cost.map((entry, index) => (<Cell key={`cell-${index}`} fill={entry.color} stroke="white" strokeWidth={2} />))}
                  </Pie>
                  <Tooltip formatter={(value: number, name: string) => [`₩${Math.round(value).toLocaleString()}`, name]} />
                  <Legend layout="vertical" verticalAlign="middle" align="right" wrapperStyle={{fontSize: '11px'}}/>
                </PieChart>
              </ResponsiveContainer>
              <div className="absolute top-0 right-0 text-right bg-orange-50/50 p-2 rounded-lg border border-orange-100 shadow-sm"><div className="text-[10px] text-orange-600 font-bold uppercase">Total Costs</div><div className="text-lg font-bold text-[#5d4037]">₩{Math.round(totalCost / 10000).toLocaleString()}만</div></div>
           </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-orange-100">
        <div className="flex justify-between items-center mb-6"><h2 className="text-lg font-bold text-[#5d4037]">수익 추이 및 BEP 분석 (12개월 전망)</h2></div>
        <div className="h-[450px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={mainChartData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }} barGap={2}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f9f2ed" />
              <XAxis dataKey="month" tickFormatter={(val) => `M+${val}`} stroke="#8d6e63" />
              <YAxis yAxisId="left" stroke="#8d6e63" tickFormatter={(val) => `${val / 10000}만`} />
              <Tooltip formatter={(value: number, name: string) => name === '누적 손익' ? [`₩${Math.round(value).toLocaleString()}`, name] : [`₩${Math.abs(Math.round(value)).toLocaleString()}`, name]} />
              <Legend verticalAlign="bottom" height={36} content={() => (<div className="flex justify-center gap-6 mt-4 text-[11px] font-bold text-[#5d4037]"><div className="flex items-center gap-2"><div className="w-3 h-3 bg-orange-600"></div><span>매출원</span></div><div className="flex items-center gap-2"><div className="w-3 h-3 bg-[#d7ccc8]"></div><span>지출원</span></div><div className="flex items-center gap-2"><div className="w-4 h-0.5 bg-[#3e2723]"></div><span>누적 자산 추이</span></div></div>)} />
              <ReferenceLine yAxisId="left" y={0} stroke="#5d4037" strokeDasharray="3 3" />
              <Bar yAxisId="left" dataKey="cafeRevenue" stackId="revenue" fill={CHART_COLORS.revenue.cafe} barSize={20} />
              <Bar yAxisId="left" dataKey="spaceRevenue" stackId="revenue" fill={CHART_COLORS.revenue.space} barSize={20} />
              <Bar yAxisId="left" dataKey="wineRevenue" stackId="revenue" fill={CHART_COLORS.revenue.wine} barSize={20} radius={[4, 4, 0, 0]} />
              <Bar yAxisId="left" dataKey="laborCost" stackId="cost" fill={CHART_COLORS.cost.labor} barSize={20} />
              <Bar yAxisId="left" dataKey="cafeCOGS" stackId="cost" fill={CHART_COLORS.cost.cafe} barSize={20} />
              <Bar yAxisId="left" dataKey="wineCOGS" stackId="cost" fill={CHART_COLORS.cost.wine} barSize={20} />
              <Bar yAxisId="left" dataKey="utilityCost" stackId="cost" fill={CHART_COLORS.cost.utility} barSize={20} />
              <Bar yAxisId="left" dataKey="otherFixedCost" stackId="cost" fill={CHART_COLORS.cost.fixed} barSize={20} radius={[0, 0, 4, 4]} />
              <Line yAxisId="left" type="monotone" dataKey="cumulativeProfit" name="누적 손익" stroke={CHART_COLORS.profit} strokeWidth={3} dot={{ r: 3, fill: CHART_COLORS.profit }} />
            </ComposedChart>
          </ResponsiveContainer>
        </div>
      </div>

       <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-xl font-bold text-[#5d4037] flex items-center gap-2">
            <FileText className="text-orange-600" size={24} /> 
            월간 재무 리포트 상세
          </h3>
          <span className="text-[10px] text-orange-400 font-black uppercase tracking-widest bg-orange-50 px-3 py-1 rounded-full">Currency: KRW</span>
        </div>
        <FinancialTable data={monthlyData} />
      </div>
    </div>
  );
};
